// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore generated by opennextjs-cloudflare during cf:build
import generatedOpenNextWorker, { BucketCachePurge, DOQueueHandler, DOShardedTagCache } from "./.open-next/worker.js";

type OpenNextWorkerModule = {
  fetch(request: Request, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<Response>;
};

type WorkerExecutionContext = {
  waitUntil(promise: Promise<unknown>): void;
  passThroughOnException?(): void;
};

type WorkerScheduledController = {
  cron: string;
  scheduledTime: number;
};

type WorkerHandler = {
  fetch(request: Request, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<Response>;
  scheduled(controller: WorkerScheduledController, env: CloudflareEnv, ctx: WorkerExecutionContext): Promise<void>;
};

const openNextWorker = generatedOpenNextWorker as OpenNextWorkerModule;
const SITEMAP_EDGE_CACHE_NAME = "gospelchannel-sitemaps";
const HTML_EDGE_CACHE_NAME = "gospelchannel-html-v2";
const HTML_EDGE_CACHE_TTL_SECONDS = 3600;
const HTML_EDGE_CACHE_SWR_SECONDS = 86400;
const AUTH_COOKIE_PATTERN = /(?:^|;\s*)(?:better-auth|session|auth)/i;

// OpenNext on Cloudflare returns 200 OK even when Next.js notFound() triggers
// from inside server components. The rendered HTML carries the not-found.tsx
// content but the status line stays 200, which Google reads as low-quality
// indexable. We sniff the rendered HTML for a sentinel element placed in
// src/app/not-found.tsx and rewrite the status to 404 when present.
//
// We only inspect bodies of GET responses with text/html content-type, and
// only the first 16KB — the sentinel sits in the <body> right after <main>'s
// opening container, well within that budget.
const NOT_FOUND_SENTINEL = 'data-gc-not-found="1"';
const SENTINEL_SCAN_BYTES = 16384;

async function fixNotFoundStatus(request: Request, response: Response): Promise<Response> {
  if (request.method !== "GET") return response;
  if (response.status !== 200) return response;
  const contentType = response.headers.get("content-type") ?? "";
  if (!contentType.includes("text/html")) return response;
  if (!response.body) return response;

  // Reads body from the stream and rebuilds a Response. Skipping clone() —
  // on Workers a cloned body can come back empty for streamed responses.
  const reader = response.body.getReader();
  const chunks: Uint8Array[] = [];
  let total = 0;
  let scanBuffer = "";
  let found = false;
  const decoder = new TextDecoder("utf-8", { fatal: false });

  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    chunks.push(value);
    total += value.byteLength;
    if (!found && scanBuffer.length < SENTINEL_SCAN_BYTES) {
      scanBuffer += decoder.decode(value, { stream: true });
      if (scanBuffer.includes(NOT_FOUND_SENTINEL)) {
        found = true;
      }
    }
  }

  const merged = new Uint8Array(total);
  let offset = 0;
  for (const chunk of chunks) {
    merged.set(chunk, offset);
    offset += chunk.byteLength;
  }

  const headers = new Headers(response.headers);
  headers.delete("content-encoding");
  headers.delete("content-length");

  if (!found) {
    return new Response(merged, { status: 200, statusText: response.statusText, headers });
  }

  headers.set("cache-control", "no-store");
  return new Response(merged, { status: 404, statusText: "Not Found", headers });
}

function isSitemapRequest(request: Request): boolean {
  if (request.method !== "GET") {
    return false;
  }

  const { pathname } = new URL(request.url);
  return pathname === "/sitemap.xml" || pathname.startsWith("/sitemap-chunk/");
}

function shouldEdgeCache(response: Response): boolean {
  if (!response.ok) {
    return false;
  }

  const cacheControl = response.headers.get("cache-control")?.toLowerCase() ?? "";
  return cacheControl.includes("public") && !cacheControl.includes("no-store");
}

function isHtmlCacheableRequest(request: Request): boolean {
  if (request.method !== "GET") return false;

  // Skip authenticated users (admin views, claim flows)
  const cookieHeader = request.headers.get("cookie") ?? "";
  if (AUTH_COOKIE_PATTERN.test(cookieHeader)) return false;

  // Skip Next.js RSC client-side navigation payloads
  if (request.headers.get("rsc")) return false;
  if (request.headers.get("next-router-state-tree")) return false;
  if (request.headers.get("next-router-prefetch")) return false;
  if (request.headers.get("next-router-segment-prefetch")) return false;

  const { pathname } = new URL(request.url);

  // Sitemaps have their own edge cache
  if (pathname === "/sitemap.xml" || pathname.startsWith("/sitemap-chunk/")) return false;

  // Static content pages
  if (
    pathname === "/" ||
    pathname === "/about" ||
    pathname === "/for-churches" ||
    pathname === "/contact" ||
    pathname === "/privacy"
  ) {
    return true;
  }
  if (pathname.startsWith("/guides")) return true;

  // Church directory + facet listings (read searchParams → otherwise force-dynamic)
  if (pathname === "/church") return true;
  if (
    pathname.startsWith("/church/country/") ||
    pathname.startsWith("/church/city/") ||
    pathname.startsWith("/church/style/") ||
    pathname.startsWith("/church/denomination/")
  ) {
    return true;
  }

  // Compare + network detail pages
  if (pathname.startsWith("/compare/")) return true;
  if (pathname.startsWith("/network/")) return true;

  // Prayerwall (public)
  if (pathname.startsWith("/prayerwall")) return true;

  // Church detail page only (exclude /manage, /embed, /claim, /suggest)
  const churchDetailMatch = pathname.match(/^\/church\/([^/]+)$/);
  if (churchDetailMatch) {
    const slug = churchDetailMatch[1];
    if (slug === "suggest" || slug === "country" || slug === "city" || slug === "style" || slug === "denomination") {
      return false;
    }
    return true;
  }

  return false;
}

async function fetchWithHtmlEdgeCache(
  request: Request,
  env: CloudflareEnv,
  ctx: WorkerExecutionContext,
): Promise<Response> {
  const edgeCache = await caches.open(HTML_EDGE_CACHE_NAME);
  const cacheKey = new Request(request.url, { method: "GET" });

  const cached = await edgeCache.match(cacheKey);
  if (cached) {
    const hitHeaders = new Headers(cached.headers);
    hitHeaders.set("x-edge-cache", "HIT");
    const hit = new Response(cached.body, {
      status: cached.status,
      statusText: cached.statusText,
      headers: hitHeaders,
    });
    // Old cache entries from before the 404 fix may still carry status 200
    // with Not Found content. Rewrite them on the way out.
    return fixNotFoundStatus(request, hit);
  }

  const rawResponse = await openNextWorker.fetch(request, env, ctx);
  const response = await fixNotFoundStatus(request, rawResponse);
  const contentType = response.headers.get("content-type") ?? "";
  const isHtml = contentType.includes("text/html");
  const setsCookie = response.headers.has("set-cookie");

  if (response.ok && isHtml && !setsCookie) {
    const overrideHeaders = new Headers(response.headers);
    overrideHeaders.set(
      "cache-control",
      `public, max-age=0, s-maxage=${HTML_EDGE_CACHE_TTL_SECONDS}, stale-while-revalidate=${HTML_EDGE_CACHE_SWR_SECONDS}`,
    );
    overrideHeaders.set("x-edge-cache", "MISS");

    const overridden = new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: overrideHeaders,
    });

    ctx.waitUntil(edgeCache.put(cacheKey, overridden.clone()));
    return overridden;
  }

  return response;
}

async function fetchWithEdgeCache(
  request: Request,
  env: CloudflareEnv,
  ctx: WorkerExecutionContext,
): Promise<Response> {
  if (isSitemapRequest(request)) {
    return fetchWithSitemapEdgeCache(request, env, ctx);
  }
  if (isHtmlCacheableRequest(request)) {
    return fetchWithHtmlEdgeCache(request, env, ctx);
  }
  // Non-cached paths still need the 200→404 rewrite for SEO hygiene.
  const response = await openNextWorker.fetch(request, env, ctx);
  return fixNotFoundStatus(request, response);
}

async function fetchWithSitemapEdgeCache(
  request: Request,
  env: CloudflareEnv,
  ctx: WorkerExecutionContext,
): Promise<Response> {
  if (!isSitemapRequest(request)) {
    return openNextWorker.fetch(request, env, ctx);
  }

  const edgeCache = await caches.open(SITEMAP_EDGE_CACHE_NAME);
  const cacheKey = new Request(request.url, { method: "GET" });
  const cached = await edgeCache.match(cacheKey);
  if (cached) {
    return cached;
  }

  const response = await openNextWorker.fetch(request, env, ctx);
  if (shouldEdgeCache(response)) {
    ctx.waitUntil(edgeCache.put(cacheKey, response.clone()));
  }

  return response;
}

async function runScheduledCron(env: CloudflareEnv, ctx: WorkerExecutionContext, path: string) {
  const origin = env.NEXT_PUBLIC_SITE_URL || "https://gospelchannel.com";
  const url = new URL(path, origin);
  const headers = new Headers();

  if (env.CRON_SECRET) {
    headers.set("authorization", `Bearer ${env.CRON_SECRET}`);
  }

  const response = await openNextWorker.fetch(
    new Request(url.toString(), {
      method: "GET",
      headers,
    }),
    env,
    ctx,
  );

  if (!response.ok) {
    const details = (await response.text().catch(() => response.statusText)).slice(0, 200);
    throw new Error(`Cron ${path} failed with ${response.status}: ${details}`);
  }
}

export { BucketCachePurge, DOQueueHandler, DOShardedTagCache };

const worker: WorkerHandler = {
  fetch: fetchWithEdgeCache,
  async scheduled(controller: WorkerScheduledController, env: CloudflareEnv, ctx: WorkerExecutionContext) {
    if (controller.cron === "23 6 * * *") {
      await runScheduledCron(env, ctx, "/api/cron/push-indexing");
    } else {
      await runScheduledCron(env, ctx, "/api/cron/sync");
    }
  },
};

export default worker;
